/// <summary>
///    The <c>ETGPurchPurchaseOrderControllerExtension</c> This class will opens the new PurchPurchaseOrderETG report instead of Standard purchase order report
/// </summary>


class ETGPurchPurchaseOrderControllerExtension extends PurchPurchaseOrderController
{
}

Method.Source:
public static ETGPurchPurchaseOrderControllerExtension construct()
{
    return new ETGPurchPurchaseOrderControllerExtension();
}

public static void main(Args _args)
{

        SrsReportRunController formLetterController = ETGPurchPurchaseOrderControllerExtension::construct();
        ETGPurchPurchaseOrderControllerExtension controller = formLetterController;
        controller.parmReportName(ssrsReportStr(PurchPurchaseOrderETG, OrderPurchaseReport));
        controller.parmArgs(_args);
        controller.startOperation();

}
